import React from "react";

export default function Footer() {
  return (
    <>
      <footer className="w-full bg-gradient-to-r from-black via-gray-900 to-black py-6 px-4 relative shadow-lg">
        {/* الشريط الملون المتحرك في الأعلى */}
        <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-blue-600 via-red-500 via-yellow-400 via-cyan-400 to-green-500 bg-[length:200%_100%] animate-[gradient_3s_ease_infinite]"></div>

        <div className="container mx-auto px-4">
          <div className="flex justify-evenly items-center flex-wrap gap-8 max-w-2xl mx-auto">
            <a 
              href="#" 
              className="text-5xl md:text-6xl transition-all duration-300 hover:scale-110 hover:-translate-y-2"
              style={{ color: "#1877F2" }}
            >
              <i className="fab fa-facebook"></i>
            </a>
            <a 
              href="#" 
              className="text-5xl md:text-6xl transition-all duration-300 hover:scale-110 hover:-translate-y-2"
              style={{ color: "#fd1d1d" }}
            >
              <i className="fab fa-instagram"></i>
            </a>
            <a 
              href="#" 
              className="text-5xl md:text-6xl transition-all duration-300 hover:scale-110 hover:-translate-y-2"
              style={{ color: "#fffc00" }}
            >
              <i className="fab fa-snapchat"></i>
            </a>
            <a 
              href="#" 
              className="text-5xl md:text-6xl transition-all duration-300 hover:scale-110 hover:-translate-y-2"
              style={{ color: "#4de8f4" }}
            >
              <i className="fab fa-tiktok"></i>
            </a>
            <a 
              href="#" 
              className="text-5xl md:text-6xl transition-all duration-300 hover:scale-110 hover:-translate-y-2"
              style={{ color: "#25d366" }}
            >
              <i className="fab fa-whatsapp"></i>
            </a>
          </div>
        </div>
      </footer>

      {/* إضافة حركة التدرج للشريط الملون */}
      <style>{`
        @keyframes gradient {
          0% { background-position: 0% 50%; }
          50% { background-position: 100% 50%; }
          100% { background-position: 0% 50%; }
        }
      `}</style>
    </>
  );
}
